INSERT INTO projects (title,slug,stall_area_sqm,stall_area_sqft,stall_height_m,floors,build_year,city,exhibition_id,client_id,description,design_brief,ai_summary,design_style,materials_used,special_features,awards,status,is_featured,display_order) VALUES ('Acrrynics 18 SQM 3 Side Open Stall Exhibition Stall Design at FITAG Tech Expo - IT Show, Gandhinagar 2025','acrrynics-18-sqm-custom-exhibition-stall-fitag-tech-expo-it-show-gandhinagar-2025',18,193.75,4,1,2025,'Gandhinagar',(SELECT id FROM exhibitions WHERE slug='fitag-tech-expo-it-show'),(SELECT id FROM clients WHERE slug='acrrynics'),'Approach Media designed and fabricated an 18 SQM 3 side open stall exhibition stall for Acrrynics at FITAG Tech Expo - IT Show, Helipad Ground, Gandhinagar. The booth presents a compact Acronis and Nilmay branded IT security exhibit with illuminated counters, cyber cloud communication panels, blue flooring, and a clean meeting-led layout. The stall was planned for strong brand recall, clear product visibility, easy visitor movement, and search-friendly portfolio discovery for security devises, it, hardware, television exhibition projects in Gandhinagar, India.','Create an 18 SQM 3 side open stall custom exhibition stall for Acrrynics that communicates technology, product credibility, and visitor engagement at FITAG Tech Expo - IT Show. The design needed visible branding, product-led storytelling, practical discussion areas, and a premium finish suitable for a busy expo environment.','Acrrynics exhibition stall by Approach Media at FITAG Tech Expo - IT Show, Gandhinagar: 18 SQM 3 side open stall booth with clean technology booth with blue-white cyber security branding, designed for product display, lead generation, visitor interaction, and high search relevance around custom exhibition stall design and fabrication in Gujarat.','Clean technology booth with blue-white cyber security branding','["Laminated wooden structure", "printed vinyl graphics", "acrylic logo panels", "LED backlit fascia", "carpet flooring", "display lighting"]','["Backlit fascia", "Acronis/Nilmay brand panels", "product communication wall", "meeting seating", "illuminated counter", "open visitor access"]',NULL,'published',true,20) ON CONFLICT (slug) DO NOTHING;
